// Aceita {campanha_envio_id} direto OU {} pra varredura em lote.
// Devolve lista de envio_ids a processar.

const body = $json.body || {};
const envioEspecifico = body.campanha_envio_id;

if (envioEspecifico) {
  return [{ json: { envio_id: envioEspecifico, modo: 'single' } }];
}
return [{ json: { modo: 'batch' } }];

// Quebra array em items (substituto de SplitInBatches v3)
const arr = Array.isArray($json) ? $json : [$json];
return arr.map(e => ({ json: e }));

// Busca envio + briefing + último contato. Valida se IA está ativa.

const envio = $json;
const camp = envio.campanha;

if (!camp) return [{ json: { skip: true, reason: 'sem campanha' } }];
if (!['ativa','em_andamento'].includes(camp.status)) return [{ json: { skip: true, reason: `campanha ${camp.status}` } }];

const briefing = camp.briefing_ia || {};
if (!briefing.ia_ativa) return [{ json: { skip: true, reason: 'ia_ativa=false' } }];

return [{
  json: {
    envio_id: envio.id,
    campanha_id: envio.campanha_id,
    lead_id: envio.lead_id,
    telefone: envio.telefone,
    campanha_nome: camp.nome,
    mensagem_inicial: camp.mensagem,
    briefing,
    primeira_msg_contato_em_lock: envio.primeira_msg_contato_em,
  }
}];

// Extrai contact_id do resultado
const envio = $('Validar IA ativa').item.json;
const arr = Array.isArray($json) ? $json : [$json];
const contact = arr[0];

if (!contact?.id) {
  return [{ json: { ...envio, skip: true, reason: 'contact não encontrado pelo telefone' } }];
}
return [{ json: { ...envio, contact_id: contact.id } }];

// Monta prompt Gemini — adaptado pro briefing v9 do GSS (compat com legacy).
// Adições v9 (todas opcionais, retrocompat total):
//   persona_contexto, oportunidade (nome_servico/hospital/cidade/etc),
//   cidade_info, link_video, ajuda_custo_regra, handoff_gatilhos.

const envio = $('Validar IA ativa').item.json;
const rawMsgs = Array.isArray($json) ? $json : (Array.isArray($input?.all?.()) ? $input.all().map(i => i.json).filter(x => x?.text !== undefined) : []);
const msgs = rawMsgs.slice().reverse();

const b = envio.briefing || {};

// Compat: persona aceita persona_contexto (v9) ou persona (legacy)
const persona = b.persona_contexto || b.persona ||
  'Você é da equipe do Dr. Maikon Madeira — cirurgião cardíaco em Itajaí/SC. Fala direto, sem formalidade, como colega. Nunca mencione que é IA, bot ou automação.';
const contexto = b.contexto || '';
const objetivo = b.objetivo || 'Qualificar o interesse do contato e escalar pra humano quando fizer sentido.';

function tagBlock(name, content) {
  if (!content || (typeof content === 'string' && !content.trim())) return '';
  return '
<' + name + '>
' + content + '
</' + name + '>';
}

// Bloco <oportunidade> v9 — só aparece se tiver pelo menos 1 campo "core" v9
// (nome_servico, hospital, cidade, etc). Se briefing legacy tem só beneficios,
// vai renderizar como <beneficios> abaixo, não como <oportunidade>.
const temCampoV9 = !!(b.nome_servico || b.hospital || b.cidade || b.tipo_servico || b.contratacao || b.requisitos || b.estrutura || b.inicio_servico || b.pagamento || b.valor_por);
const opPartes = [];
if (temCampoV9) {
  if (b.nome_servico) opPartes.push('Serviço: ' + b.nome_servico);
  if (b.hospital) opPartes.push('Hospital/local: ' + b.hospital);
  if (b.cidade) opPartes.push('Cidade: ' + b.cidade);
  if (b.tipo_servico) opPartes.push('Tipo: ' + b.tipo_servico);
  if (b.contratacao) opPartes.push('Contratação: ' + b.contratacao);
  if (b.requisitos) opPartes.push('Requisitos: ' + b.requisitos);
  if (b.estrutura) opPartes.push('Estrutura: ' + b.estrutura);
  if (b.inicio_servico) opPartes.push('Início: ' + b.inicio_servico);
  if (b.pagamento) opPartes.push('Pagamento: ' + b.pagamento);
  if (b.valor_por) opPartes.push('Unidade de cobrança: ' + b.valor_por + ' (USO INTERNO — IA não passa valor)');
  if (Array.isArray(b.beneficios) && b.beneficios.length > 0) {
    opPartes.push('Benefícios:
' + b.beneficios.map(function(x){return '  - ' + x;}).join('
'));
  }
}
const oportunidade = opPartes.length > 0 ? tagBlock('oportunidade', opPartes.join('
')) : '';

const cidadeInfo = b.cidade_info ? tagBlock('cidade_info', String(b.cidade_info).trim()) : '';

const videoCidade = b.link_video ? tagBlock('video_cidade',
  'Há um vídeo curto da cidade disponível: ' + b.link_video + '

' +
  'Ofereça o vídeo APENAS quando:
' +
  '1. Médico disse que NÃO conhece a região
' +
  '2. Médico perguntou "como é a cidade?" / "vale a pena morar?"
' +
  '3. Médico demonstrou hesitação por questão de localização
' +
  '4. Conversa esfriando — usar como reengajamento

' +
  'NUNCA ofereça o vídeo na 1ª ou 2ª mensagem. NUNCA ofereça mais de 1x na conversa.'
) : '';

// beneficios legacy: só renderiza se NÃO foi pra <oportunidade> v9
const beneficiosLegacy = (Array.isArray(b.beneficios) && b.beneficios.length > 0 && !temCampoV9)
  ? tagBlock('beneficios', b.beneficios.map(function(x){return '- ' + x;}).join('
')) : '';
const objecoesBlock = (Array.isArray(b.objecoes) && b.objecoes.length > 0)
  ? tagBlock('objecoes', b.objecoes.map(function(o){return '- "' + (o.pergunta || o.objecao || '') + '": ' + (o.resposta || '');}).join('
')) : '';

// Palavras proibidas: aceita array OU string vírgula-separada
const proibidasDefault = ['moderno', 'moderna', 'tecnologia de ponta', 'de ponta', 'oportunidade única', 'projeto revolucionário', 'ambiente incrível', 'estruturar algo'];
let proibidasInput = [];
if (Array.isArray(b.palavras_proibidas)) {
  proibidasInput = b.palavras_proibidas;
} else if (typeof b.palavras_proibidas === 'string' && b.palavras_proibidas.trim()) {
  proibidasInput = b.palavras_proibidas.split(',').map(function(s){return s.trim();}).filter(Boolean);
}
const proibidasLista = [...new Set([...proibidasInput, ...proibidasDefault])];

const fluxoPassos = Array.isArray(b.fluxo_passos) && b.fluxo_passos.length > 0
  ? b.fluxo_passos
  : ['Entender o contexto do contato (quem é, situação)', 'Apresentar o serviço/proposta de forma breve', 'Qualificar interesse', 'Encaminhar pra humano quando houver fit'];

const kws = Array.isArray(b.handoff_keywords) && b.handoff_keywords.length > 0
  ? b.handoff_keywords
  : ['salario','salário','valor','remuneração','remuneracao','quanto paga','quanto custa','preço','preco'];

const handoffNome = b.handoff_nome || 'a equipe';
const handoffFrase = b.handoff_frase || 'vai te passar os detalhes.';
const handoffGatilhos = (typeof b.handoff_gatilhos === 'string' && b.handoff_gatilhos.trim()) ? b.handoff_gatilhos.trim() : '';

const ajudaCustoLinha = (typeof b.ajuda_custo_regra === 'string' && b.ajuda_custo_regra.trim())
  ? '
- ' + b.ajuda_custo_regra.trim() : '';

const checklistMinimo = Number.isInteger(b.checklist_handoff_minimo) ? b.checklist_handoff_minimo : 3;

const infoExtra = typeof b.info_extra === 'string' && b.info_extra.trim() ? tagBlock('info_extra', b.info_extra.trim()) : '';

const ultimaDoLead = msgs.filter(function(m){return !m.from_me;}).slice(-1)[0];
const textoUltima = (ultimaDoLead?.text || '').toLowerCase();
const keywordMatch = kws.some(function(k){return textoUltima.includes(k.toLowerCase());});

const handoffSection = handoffGatilhos
  ? 'GATILHOS DE HANDOFF (definidos pelo briefing):
' + handoffGatilhos
  : 'QUANDO fazer handoff:
- Contato aceitou explicitamente conversar com humano
- Contato perguntou sobre valor/remuneração/preço (NÃO responde valor você mesmo)
- Contato demonstrou interesse forte e pediu próximos passos';

const systemPrompt = '<prompt versao="maikonect-v2">
<contexto>
' + persona + (contexto ? '
' + contexto : '') + '
</contexto>

<objetivo>
' + objetivo + '
</objetivo>' + oportunidade + cidadeInfo + videoCidade + '

<naturalidade>
REGRAS DE FALA HUMANA — contatos percebem robô na hora:
- Aberturas variam: "oi", "opa", "e aí", "bacana", "boa". NUNCA "Olá!" ou "Olá, doutor!".
- SEM emoji estruturado, SEM markdown (negrito, itálico), SEM listas/bullets, SEM numeração.
- Pontuação humana e descontraída: vírgulas opcionais omitidas, abreviações naturais ok (vc, tb, pq, blz).
- Comprimento variado: ora 1 frase curta, ora 2 frases. Evite uniformidade. Evite parágrafos longos.
- Não cumprimente a cada mensagem. Conversa fluida não faz isso.
- Sem "espero ter ajudado", "fico à disposição", "qualquer dúvida estou aqui" — clichês de bot.
- Se contato fala curto, responde curto. Se elaborou, pode elaborar mais.
- Pode reagir com "show", "bacana", "legal" — com moderação.
</naturalidade>

<engajamento_proativo>
Quando o contato demonstrar curiosidade ("me conta mais", "como funciona", "onde é"), responde com FATO + PERGUNTA de aprofundamento. Não responda seco. Mas sem floreio vendedor.

Use SEMPRE que relevante: fatos concretos do briefing, nome do serviço, cidade, requisitos. Entregue o que pode engajar.
</engajamento_proativo>' + beneficiosLegacy + objecoesBlock + '

<precisao_tecnica>
Use os termos EXATOS do bloco <oportunidade> ao perguntar requisitos. Ex: se o briefing diz "RQE em Pediatria", você pergunta "tem RQE em Pediatria?" — não suaviza pra "tem certificação?". Termos técnicos do briefing são literais, não traduzir.
</precisao_tecnica>

<fluxo>
REGRA ABSOLUTA: Leia TODO o histórico. NUNCA repita pergunta já respondida.
"Sim" = passo concluído. Avance. 1 pergunta por vez.

Passos do fluxo (guia, não script fechado):
' + fluxoPassos.map(function(p,i){return (i+1) + '. ' + p;}).join('
') + '
</fluxo>

<antes_de_handoff>
🛑 REGRA DURA — NÃO mencione "passar contato", "vou te passar pra ' + handoffNome + '" ou qualquer handoff ANTES de ter explicado o suficiente na conversa.

CHECKLIST mínimo de itens trocados na conversa ANTES de qualquer menção a handoff:
  □ Contato entendeu o que você está oferecendo
  □ Você confirmou se ele tem interesse ou fit
  □ Pelo menos 1 pergunta/fato concreto do briefing foi trocado
  □ Contato não demonstrou recusa

Se MENOS DE ' + checklistMinimo + ' desses itens foram trocados, NÃO ofereça handoff. Continue explicando, perguntando, engajando.

EXCEÇÃO: se o contato disser literalmente "me liga", "me passa pro responsável", "quero fechar", "quem cuida disso pra eu falar" → handoff imediato é OK.
</antes_de_handoff>

<handoff>
' + handoffSection + '

COMO fazer:
- "Posso passar pra ' + handoffNome + '? ' + handoffFrase + '"
- Após confirmar: "Show, te chamam em breve."

NUNCA:
- Mandar "vou passar pra X" duas vezes em menos de 5 msgs
- Empurrar handoff se contato está explorando sem pedir
- Insistir se ignorou o pedido
</handoff>

<regras>
- 1 a 2 mensagens por turno, curtas.
- NUNCA passar valor/preço/salário você mesmo. Se perguntarem, redirecione: "' + handoffNome + ' cuida disso, ' + handoffFrase + '"' + ajudaCustoLinha + '
</regras>

<anti_promessa>
PALAVRAS PROIBIDAS: ' + proibidasLista.map(function(p){return '"' + p + '"';}).join(', ') + '

Substitua por fatos verificáveis. Se for usar adjetivo vendedor, CORTE.
Fale SÓ dos fatos do briefing: estrutura real, cidade real, dados reais.
</anti_promessa>

<anti_loop>
Antes de responder, leia TODO o histórico. Se o contato já informou algo, NÃO pergunte de novo. Avance.
Um "Sim" como resposta a pergunta sua = passo concluído. Registre e avance.
Se o contato mandou 2+ msgs ou uma msg com resposta + pergunta: extraia TUDO antes de responder.
</anti_loop>

<contato_dirige>
O CONTATO dirige a conversa. Seu fluxo é um guia.
- Se ele quer saber mais: responda em profundidade antes de voltar ao fluxo.
- Se faz pergunta técnica que você tem resposta no briefing: RESPONDA direto, não jogue pro handoff.
- Empurrar handoff cedo OU repetidamente → contato percebe pressa → lead perdido.
- Pressa é bot. Calma é humano.
</contato_dirige>' + infoExtra + '

<maturidade>
Avalie a maturidade do lead pelas mensagens dele:
- "frio": só leu, respondeu vago/curto, sem pergunta concreta
- "morno": fez perguntas específicas sobre o serviço, requisitos ou cidade
- "quente": confirmou perfil, pediu próximos passos, perguntou sobre fechamento ou valor

Retorne em maturidade_lead.
</maturidade>

<saida>
Retorne APENAS JSON válido:
{"messages":["msg1","msg2"],"alerta_lead":false,"motivo_alerta":"","conversa_encerrada":false,"maturidade_lead":"frio|morno|quente"}

- "messages": ARRAY de 1 a 2 mensagens curtas. Cada uma vira msg separada no WhatsApp.
- "alerta_lead"=true APENAS quando: contato aceitou handoff OU perguntou sobre valor/remuneração/preço.
- "motivo_alerta": string curta descrevendo o porquê do alerta (ou vazia).
- "conversa_encerrada"=true quando: contato recusou ou pediu pra parar.
- "maturidade_lead": "frio" | "morno" | "quente" — sua avaliação atual.
</saida>
</prompt>';

const transcricao = msgs.map(function(m){
  const who = m.from_me ? 'EQUIPE' : 'CONTATO';
  const tg = m.message_type && m.message_type !== 'text' ? ' [' + m.message_type + ']' : '';
  return who + tg + ': ' + (m.text || '(sem texto)');
}).join('
');

const warn = keywordMatch ? '

[ALERTA: detectamos palavra-chave de handoff (valor/preço/salário) na última msg. Considere alerta_lead=true.]' : '';

const userPrompt = '## MENSAGEM INICIAL ENVIADA PELA CAMPANHA
"' + (envio.mensagem_inicial || '(não registrada)') + '"

## HISTÓRICO DA CONVERSA (mais antigo primeiro)
' + (transcricao || '(sem histórico — essa é a primeira resposta do contato)') + warn + '

RESPONDA APENAS À ÚLTIMA MENSAGEM DO CONTATO. NÃO REPITA PERGUNTAS JÁ RESPONDIDAS. RETORNE O JSON.';

return [{
  json: {
    ...envio,
    _prompt_system: systemPrompt,
    _prompt_user: userPrompt,
    _keyword_match: keywordMatch,
    _last_lead_text: ultimaDoLead?.text || '',
    _gemini_body: {
      contents: [
        { role: 'user', parts: [{ text: systemPrompt + '

---

' + userPrompt }] }
      ],
      generationConfig: {
        temperature: 0.7,
        topP: 0.9,
        responseMimeType: 'application/json',
        responseSchema: {
          type: 'OBJECT',
          properties: {
            messages: { type: 'ARRAY', items: { type: 'STRING' } },
            alerta_lead: { type: 'BOOLEAN' },
            motivo_alerta: { type: 'STRING' },
            conversa_encerrada: { type: 'BOOLEAN' },
            maturidade_lead: { type: 'STRING' }
          },
          required: ['messages','alerta_lead','motivo_alerta','conversa_encerrada','maturidade_lead']
        }
      }
    }
  }
}];

// Parse resposta Gemini (JSON estruturado via responseSchema)
const envio = $('Montar prompt Gemini').item.json;
const raw = $json;
const text = raw?.candidates?.[0]?.content?.parts?.[0]?.text || '';

let parsed;
try {
  const clean = text.replace(/^```json\s*/i, '').replace(/```$/, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  return [{ json: { ...envio, erro: 'JSON inválido Gemini', raw: text.slice(0, 300) } }];
}

return [{
  json: {
    ...envio,
    ia_messages: Array.isArray(parsed.messages) && parsed.messages.length > 0 ? parsed.messages : ['Ok!'],
    alerta_lead: !!parsed.alerta_lead,
    motivo_alerta: parsed.motivo_alerta || '',
    conversa_encerrada: !!parsed.conversa_encerrada,
    deve_fazer_handoff: !!(envio._keyword_match || parsed.alerta_lead),
    maturidade_lead: parsed.maturidade_lead || 'frio',
  }
}];

// Se o lead picou uma msg nova enquanto o Gemini estava respondendo,
// o primeira_msg_contato_em mudou — aborta pra não responder desatualizado.

const envio = $('Parse resposta').item.json;
const atual = Array.isArray($json) ? $json[0] : $json;
const agoraEm = atual?.primeira_msg_contato_em;

if (agoraEm !== envio.primeira_msg_contato_em_lock) {
  return [{ json: { ...envio, abortado: true, reason: 'debounce invalidado (lead picou msg nova)' } }];
}

return [{ json: envio }];

// Busca instância que a IA usa pra responder (briefing.handoff_numero_chip
// OU primeiro chip_ids da campanha). Normaliza telefone.

const envio = $json;
if (envio.abortado) return [{ json: envio }];

const b = envio.briefing || {};
const chipId = b.handoff_numero_chip;

// Normaliza telefone pro padrão +55
function normalize(raw) {
  let d = (raw || '').replace(/\D/g, '');
  if (d.startsWith('55') && d.length > 11) d = d.slice(2);
  if (d.length < 10 || d.length > 11) return null;
  if (d.length === 10) {
    const c = parseInt(d[2], 10);
    if (c >= 6) d = d.slice(0, 2) + '9' + d.slice(2);
  }
  return '55' + d;
}

const phone = normalize(envio.telefone);
if (!phone) return [{ json: { ...envio, abortado: true, reason: 'telefone inválido' } }];

return [{ json: { ...envio, phone_normalized: phone, chip_ia_id: chipId } }];

// Dispara cada msg via Evolution com presence 'composing' + delay natural.
// NOTA: n8n node limits — pra não complicar com loop interno, enviamos
// somente a primeira msg. Se precisar mandar múltiplas, iterate external.

const envio = $('Preparar envio').item.json;
if (envio.abortado) return [{ json: envio }];

const instancia = Array.isArray($json) ? $json[0] : $json;
const instanciaNome = instancia?.nome_instancia;
if (!instanciaNome) return [{ json: { ...envio, abortado: true, reason: 'sem instância IA disponível' } }];

return [{
  json: {
    ...envio,
    instancia_nome: instanciaNome,
    primeira_msg: (envio.ia_messages && envio.ia_messages[0]) || 'Ok!',
    todas_msgs: envio.ia_messages || [],
  }
}];

// Envia TODAS as msgs da IA com presence+delay humanizado.
// Depois, se deve_fazer_handoff, manda alerta pro handoff_telefone configurado.
// Usa helpers.httpRequest do n8n (mais confiável que fetch em Code node).

const envio = $json;
if (envio.abortado) return [{ json: envio }];

// Lê do env do container n8n (injetado via docker service env)
const evoBase = $env.EVOLUTION_API_URL;
const evoKey = $env.EVOLUTION_API_KEY;
const instancia = envio.instancia_nome;
const phone = envio.phone_normalized;
const msgs = (envio.todas_msgs && envio.todas_msgs.length > 0) ? envio.todas_msgs : [envio.primeira_msg || 'Ok'];

// Captura helpers no scope de cima pra não perder contexto em nested funcs
const httpRequest = this.helpers.httpRequest.bind(this.helpers);

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

async function evoCall(path, body) {
  try {
    const resp = await httpRequest({
      method: 'POST',
      url: `${evoBase}${path}`,
      headers: { 'Content-Type': 'application/json', 'apikey': evoKey },
      body,
      json: true,
      returnFullResponse: true,
      timeout: 15000,
    });
    return { ok: resp.statusCode >= 200 && resp.statusCode < 300, status: resp.statusCode, body: resp.body };
  } catch (e) {
    const msg = String(e && e.message || e).slice(0, 300);
    const status = e && e.statusCode;
    return { ok: false, err: msg, status };
  }
}

async function sendPresence(num, text) {
  const delay = Math.max(1500, Math.min(4500, text.length * 60));
  await evoCall(`/chat/sendPresence/${encodeURIComponent(instancia)}`, {
    number: num, presence: 'composing', delay
  });
  await sleep(delay);
}

async function sendText(num, text) {
  const r = await evoCall(`/message/sendText/${encodeURIComponent(instancia)}`, {
    number: num, text
  });
  return r;
}

const resultados = [];

for (let i = 0; i < msgs.length; i++) {
  const text = msgs[i];
  if (!text || typeof text !== 'string') continue;
  await sendPresence(phone, text);
  const r = await sendText(phone, text);
  resultados.push({ to: 'lead', text, ok: r.ok, status: r.status, err: r.err, wa_message_id: r.body?.key?.id || null });
  if (i < msgs.length - 1) await sleep(900 + Math.random() * 1500);
}

let handoff_enviado = false;
let handoff_count = 0;
if (envio.deve_fazer_handoff) {
  const briefing = envio.briefing || {};
  // Suporta array novo + string legada (retrocompat)
  const rawList = Array.isArray(briefing.handoff_telefones) && briefing.handoff_telefones.length > 0
    ? briefing.handoff_telefones
    : (briefing.handoff_telefone ? [briefing.handoff_telefone] : []);

  function normalizeHandoff(raw) {
    let d = (raw || '').replace(/\D/g, '');
    if (d.startsWith('55') && d.length > 11) d = d.slice(2);
    if (d.length !== 10 && d.length !== 11) return null;
    if (d.length === 10) {
      const c = parseInt(d[2], 10);
      if (c >= 6) d = d.slice(0, 2) + '9' + d.slice(2);
    }
    return '55' + d;
  }

  const normalizados = [...new Set(
    rawList.map(normalizeHandoff).filter(p => p && p !== phone)
  )];

  if (normalizados.length === 0) {
    resultados.push({ to: 'handoff', skipped: true, reason: 'nenhum handoff_telefone válido' });
  } else {
    const nomeCampanha = envio.campanha_nome || 'campanha';
    const motivo = envio.motivo_alerta || 'lead precisa de atenção';
    const txtAlerta = `🚨 *Lead pediu atenção — ${nomeCampanha}*\n\nTelefone: ${envio.telefone}\nMotivo: ${motivo}\n\nÚltima msg do lead: "${(envio._last_lead_text || '').slice(0, 200)}"\n\nAbra a conversa no CRM pra assumir.`;

    for (const handoffPhone of normalizados) {
      const rH = await sendText(handoffPhone, txtAlerta);
      resultados.push({ to: 'handoff', ok: rH.ok, phone: handoffPhone, status: rH.status, err: rH.err });
      if (rH.ok) handoff_count++;
      // Pequeno delay entre handoffs pra não bloquear o chip
      await sleep(600 + Math.random() * 400);
    }
    handoff_enviado = handoff_count > 0;
  }
}

return [{
  json: {
    ...envio,
    envio_resultados: resultados,
    total_enviadas: resultados.filter(r => r.to === 'lead' && r.ok).length,
    wa_message_ids: resultados.filter(r => r.to === 'lead' && r.ok && r.wa_message_id).map(r => r.wa_message_id),
    handoff_enviado,
    handoff_count,
  }
}];

